wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(59995532440266112)
,p_plug_name=>'Multi-Dimensional Sales Analysis'
,p_region_name=>'pt_sales_global'
,p_parent_plug_id=>wwv_flow_imp.id(59995419688266111)
,p_region_template_options=>'#DEFAULT#:js-showMaximizeButton:i-h640:t-Region--removeHeader js-removeLandmark:t-Region--scrollBody'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>10
,p_plug_display_point=>'SUB_REGIONS'
,p_query_type=>'FUNC_BODY_RETURNING_SQL'
,p_function_body_language=>'PLSQL'
,p_plug_source=>'return lib4x_pivot_table.p2_get_pivot_query_a;'
,p_plug_source_type=>'PLUGIN_LIB4X.AXT.WDR.PIVOTTABLE'
,p_plugin_init_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'function(options)',
'{',
'    options.metadata = {    ',
'        ''SEGMENT'': {',
'            type: ''string'',',
'            caption: ''Segment''',
'        },',
'        ''COUNTRY'': {',
'            type: ''string'',',
'            caption: ''Country''',
'        },',
'        ''REGION'': {',
'            type: ''string'',',
'            caption: ''Region''',
'        },',
'        ''CATEGORY'': {',
'            type: ''string'',',
'            caption: ''Product Category''',
'        },            ',
'        ''CHANNEL'': {',
'            type: ''string'',',
'            caption: ''Channel''',
'        },',
'        ''SALES_REP'': {',
'            type: ''string'',',
'            caption: ''Sales Rep''',
'        },    ',
'        ''SALES_LEVEL'': {',
'            type: ''string'',',
'            caption: ''Sales Level''',
'        },           ',
'        ''YEAR'': {',
'            type: ''number'',',
'            caption: ''Year''',
'        },',
'        ''QUARTER'': {',
'            type: ''string'',',
'            caption: ''Quarter''',
'        },',
'        ''REVENUE'': {',
'            type: ''number'',',
'            caption: ''Revenue''',
'        },',
'        ''PROFIT'': {',
'            type: ''number'',',
'            caption: ''Profit''',
'        },',
'        ''TRANSACTION_COUNT'': {',
'            type: ''number'',',
'            caption: ''Transactions''',
'        }    ',
'    };	 ',
'',
'    options.primaryReport = {',
'        slice: {',
'            expands: {',
'                "rows": [',
'                    {',
'                        "tuple": [',
'                            "REGION.Asia-Pacific"',
'                        ]',
'                    }',
'                ],',
'                "columns": [',
'                    {',
'                        "tuple": [',
'                            "SEGMENT.Enterprise"',
'                        ]',
'                    }',
'                ]',
'            }',
'        }',
'    };',
'',
'    options.alternativeReports = [',
'        {',
'            "slice": {',
'                "rows": [',
'                    {',
'                    "uniqueName": "COUNTRY"',
'                    }',
'                ],',
'                "columns": [',
'                    {',
'                    "uniqueName": "Measures"',
'                    },',
'                    {',
'                    "uniqueName": "CHANNEL"',
'                    }',
'                ],',
'                "measures": [',
'                    {',
'                    "uniqueName": "REVENUE",',
'                    "aggregation": "sum"',
'                    }',
'                ]',
'            },',
'            "options": {',
'                "grid": {',
'                    "title": "Revenue by Country / Channel"',
'                }',
'            }',
'        }',
'    ];',
'',
'    options.normalizeFilters = true;',
